import { useState } from "react";
import { BlockStack, Box, Card, Grid } from "@shopify/polaris";
import successCharge from "../../assets/images/pricing/success-charge.png";
import { useTranslation } from "react-i18next";
import { useSelector } from "react-redux";
import { Modal, TitleBar, useAppBridge } from "@shopify/app-bridge-react";
const SuccessChargeModal = ({ plan, onDismiss }) => {
  const { t } = useTranslation("pricing");
  const shopInfo = useSelector(state => state?.Auth?.shopInfo);
  const [isHovered, setIsHovered] = useState(false);

  const buttonStyle = {
    padding: "8px 16px",
    margin: "0 auto",
    borderRadius: "4px",
    border: "1px solid #005BD3",
    cursor: "pointer",
    color: isHovered ? "white" : "#303030",
    backgroundColor: isHovered ? "#005BD3" : "transparent",
  };
  const title = t("modal_charge_success.title", {
    ns: "pricing",
    plan: t(`plan.${shopInfo?.current_plan}`, {
      ns: "pricing",
    }),
  });
  return (
    <>
      <Modal open={true}>
        <TitleBar title={title}>
          <button variant="primary" onClick={onDismiss}>
            {t("continue", { ns: "translation" })}
          </button>
        </TitleBar>

        <Box paddingBlock={800} paddingInline={600}>
          <Grid columns={{ xs: 1, sm: 5 }}>
            <Grid.Cell alignItems="center" columnSpan={{ xs: 1, sm: 3}}>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  position: "relative",
                  height: "100%",
                }}
              >
                <p
                  style={{
                    margin: "0",
                    fontSize: "13px",
                    fontWeight: "500",
                  }}
                >
                  {t("modal_charge_success.content", {
                    ns: "pricing",
                  })}
                </p>
              </div>
            </Grid.Cell>
            <Grid.Cell columnSpan={{ xs: 1,sm: 2}}>
              <img src={successCharge} alt="success-charge" width={"100%"} height={"100%"} />
            </Grid.Cell>
          </Grid>
        </Box>
      </Modal>
    </>
  );
};

export default SuccessChargeModal;
